// resultimages.js

const resultImages = [
  require('./images/1angel.png'),       // 1. 순수한 직장 천사
  require('./images/2goodguy.png'),     // 2. 따뜻한 평범인
  require('./images/3rational.png'),    // 3. 냉철한 이성파
  require('./images/4pocosocio.png'),   // 4. 은근한 소시오패스
  require('./images/5sociopath.png'),   // 5. 직장 소시오패스 레전드
];

export const mainImage = require('./images/sociomain.png');

export default resultImages;
